const incoming = $input.first().json;
const body = incoming.body ?? incoming;
const query = incoming.query ?? {};
const headers = incoming.headers ?? {};
const baseUrl = body.base_url || query.base_url || 'http://host.docker.internal:8010';
const userRequest = body.user_request || body.chatInput || body.message || body.prompt || body.text || query.user_request || 'Generate an autonomous-driving scenario definition and execute the evaluation pipeline.';
const workflowToken = (typeof $vars !== 'undefined' && $vars.AV_AGENT_WEBHOOK_TOKEN)
  ? String($vars.AV_AGENT_WEBHOOK_TOKEN)
  : null;
const requiredToken = workflowToken || body.required_token || query.required_token || null;
const providedToken = headers['x-av-agent-token'] || headers['X-AV-Agent-Token'] || body.auth_token || query.auth_token || null;
if (requiredToken && providedToken !== requiredToken) {
  return [{ json: { failed: true, response_code: 401, error: 'Unauthorized scenario request. Missing or invalid x-av-agent-token/auth_token.', base_url: baseUrl, security: { auth_required: true, auth_mode: 'token_checked' } } }];
}
const reproducibility = {
  autotune_model: body.autotune_model || query.autotune_model || 'gpt-4.1-mini',
  autotune_temperature: body.autotune_temperature ?? query.autotune_temperature ?? 0.2,
  autotune_seed: body.autotune_seed ?? query.autotune_seed ?? 20260628,
  model_version_note: body.model_version_note || query.model_version_note || 'Pinned request metadata for reproducible research logging.'
};
return [{ json: {
  failed: false,
  response_code: 202,
  base_url: baseUrl,
  security: { auth_required: Boolean(requiredToken), auth_mode: requiredToken ? 'token_checked' : 'not_configured' },
  reproducibility,
  request: {
    user_request: userRequest,
    execute_simulation: body.execute_simulation ?? true,
    run_kpis: body.run_kpis ?? true,
    apply_ml: body.apply_ml ?? false,
    record: body.record ?? false,
    background: true,
    autotune_model: reproducibility.autotune_model,
    autotune_temperature: reproducibility.autotune_temperature,
    autotune_seed: reproducibility.autotune_seed,
    model_version_note: reproducibility.model_version_note
  }
} }];

const ctx = $input.first().json;
if (ctx.failed) return [{ json: ctx }];
async function requestWithRetry(options, attempts = 3) {
  let lastError;
  for (let i = 0; i < attempts; i += 1) {
    try {
      return await helpers.httpRequest(options);
    } catch (error) {
      lastError = error;
      const waitMs = 500 * Math.pow(2, i);
      await new Promise(resolve => setTimeout(resolve, waitMs));
    }
  }
  throw lastError;
}
try {
  const health = await requestWithRetry({ method: 'GET', url: `${ctx.base_url}/health`, json: true, timeout: 10000 }, 3);
  return [{ json: { ...ctx, backend_health: health } }];
} catch (error) {
  return [{ json: { ...ctx, failed: true, response_code: 503, failed_agent: 'BackendRuntimeGuard', error: `Backend health check failed after retries: ${String(error.message || error)}` } }];
}

const ctx = $input.first().json;
if (ctx.failed) return [{ json: ctx }];
async function requestWithRetry(options, attempts = 3) {
  let lastError;
  for (let i = 0; i < attempts; i += 1) {
    try {
      return await helpers.httpRequest(options);
    } catch (error) {
      lastError = error;
      const waitMs = 1000 * Math.pow(2, i);
      await new Promise(resolve => setTimeout(resolve, waitMs));
    }
  }
  throw lastError;
}
try {
  const data = await requestWithRetry({
    method: 'POST',
    url: `${ctx.base_url}/pipeline/submit`,
    headers: { 'Content-Type': 'application/json; charset=utf-8' },
    body: {
      user_request: ctx.request.user_request,
      execute_simulation: ctx.request.execute_simulation,
      run_kpis: ctx.request.run_kpis,
      apply_ml: ctx.request.apply_ml,
      record: ctx.request.record,
      background: true
    },
    json: true,
    timeout: 120000
  }, 3);
  const executionRequested = Boolean(ctx.request.execute_simulation || ctx.request.run_kpis);
  return [{ json: {
    success: true,
    response_code: 202,
    mode: 'async_background_pipeline',
    run_id: data.run_id,
    status: data.status,
    message: executionRequested
      ? 'Run accepted. CARLA/OpenCDA execution, KPI calculation, diagnosis, quality gate, readiness audit, and report generation continue in the backend background worker.'
      : 'Run prepared only. No background execution was requested because execute_simulation=false and run_kpis=false.',
    status_url: data.urls?.status || `${ctx.base_url}/pipeline/status/${data.run_id}`,
    result_url: data.urls?.run_result || `${ctx.base_url}/run/result/${data.run_id}`,
    api_docs: data.urls?.api_docs || `${ctx.base_url}/docs`,
    backend_response: data,
    security: ctx.security || null,
    reproducibility: ctx.reproducibility || null
  } }];
} catch (error) {
  return [{ json: { ...ctx, failed: true, response_code: 502, failed_agent: 'AsyncPipelineSubmitter', error: String(error.message || error) } }];
}
